#!/usr/bin/env python3
"""Generate fidelity registries from scenario_manifest.json."""

import argparse
import json
from pathlib import Path

PORT = Path(__file__).resolve().parents[2]
MANIFEST = PORT / "tools" / "scenario_manifest.json"
OUTPUT = PORT / "assets" / "scenario_registry.inc"


def scenarios():
    return json.loads(MANIFEST.read_text(encoding="utf-8"))["scenarios"]


def names(tier):
    return [item["name"] for item in scenarios()
            if tier == "full" or item["tier"] == "core"]


def render_nasm():
    rows = [
        "; DO NOT EDIT BY HAND - generated by tools/generators/gen_scenario_registry.py",
        "; Scenario gates are ordered as declared in scenario_manifest.json.",
    ]
    ordered = sorted(scenarios(),
                     key=lambda item: -len(item["build_flags"].split()))
    for index, item in enumerate(ordered):
        directive = "%ifdef" if index == 0 else "%elifdef"
        rows.extend((f"{directive} {item['port_entry_gate']}",
                     f"GBSTATE_SCENARIO equ {item['id']}"))
    rows.extend(("%elifdef DEBUG_BATTLE",
                 "GBSTATE_SCENARIO equ 7",
                 "%elifdef DEBUG_TRANSITION",
                 "GBSTATE_SCENARIO equ 1",
                 "%elifdef DEBUG_WALK_NORTH",
                 "GBSTATE_SCENARIO equ 1",
                 "%else",
                 "GBSTATE_SCENARIO equ 0",
                 "%endif", ""))
    return "\n".join(rows)


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--names", choices=("core", "full"))
    parser.add_argument("--check", action="store_true")
    args = parser.parse_args()
    if args.names:
        print(" ".join(names(args.names)))
        return
    rendered = render_nasm()
    if args.check:
        if not OUTPUT.is_file() or OUTPUT.read_text(encoding="ascii") != rendered:
            raise SystemExit(f"{OUTPUT.relative_to(PORT)} is stale; run {Path(__file__).name}")
        return
    OUTPUT.write_text(rendered, encoding="ascii")


if __name__ == "__main__":
    main()
